function $confirm(body) {
    return new Promise((resolve, reject) => {
        var id = "#pop-confirm";
        if (id.$()) return reject();
        document.body._child([
            "section#pop"._([
                "section.alert"._([
                    "strong"._(body.title),
                    (body.content) ? "p"._(body.content) : null,
                    "ul"._([
                        "li"._([
                            "i.fa-regular.fa-circle-check"._$(),
                            "確定"
                        ])._click(function () {
                            this.$parent(2).class_("show");
                            resolve();
                        }),
                        "li"._([
                            "i.fa-regular.fa-circle-xmark"._$(),
                            "取消"
                        ])._click(function () {
                            this.$parent(2).class_("show");
                            reject();
                        })
                    ])
                ])
            ])
        ]);
        setTimeout(() => {
            "pop"._class("show");
        }, 1);
    });
};

